import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import { Button, H1, H2, InputGroup, Tooltip } from "@blueprintjs/core";
import { observer } from "mobx-react";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import axios from "axios";

export const Register: FunctionComponent = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [mail, setMail] = useState("");
  const [mailConfirm, setMailConfirm] = useState("");
  const [password, setPassword] = useState("");
  const [passwordConfirm, setPasswordConfirm] = useState("");
  // const test: string = ctx.store.menu;
  const lockButton = (
    <Tooltip content={`${showPassword ? "Hide" : "Show"} Password`}>
      <Button
        className="outline-style-d"
        icon={showPassword ? "unlock" : "lock"}
        intent={Intent.WARNING}
        minimal={true}
        onClick={() => setShowPassword(!showPassword)}
      />
    </Tooltip>
  );

  function registerSubmit(e: any): void {
    e.preventDefault();
    if (formIsCorrect()) {
      axios
        .get(`http://localhost:5000/users/${mail}/${password}`)
        .then(response => {
          console.log(response.data);
          ctx.store.setName(
            response.data.firstName + " " + response.data.lastName
          );
          ctx.store.setRole(response.data.role);
          console.log(ctx.store.session.name);
        })
        .catch(error => {
          console.log(error);
        });
    }
  }

  function formIsCorrect(): boolean {
    if (!mail.match('@')) {
      alert("Mail address isn't valid.")
      return false;
    }
    if (mail !== mailConfirm) {
      alert("Mail and mail confirm must be equals !");
      return false;
    }
    if (password !== passwordConfirm) {
      alert("Password and password confirm must be equals !");
      return false;
    }
    return true;
  }

  function validateForm(): boolean {
    return mail.length > 0 && password.length > 0;
  }

  return (
    <div>
      <form onSubmit={registerSubmit}>
        <div className="login-inputgroup fx -c">
          <div className="fx -r">
            <InputGroup
              placeholder="First Name"
              required={true}
              value={firstName}
              onChange={(ev: any) => setFirstName(ev.currentTarget.value)}
            />
            <InputGroup
              placeholder="Last Name"
              required={true}
              value={lastName}
              onChange={(ev: any) => setLastName(ev.currentTarget.value)}
            />
          </div>

          <InputGroup
            placeholder="Mail address"
            required={true}
            value={mail}
            onChange={(ev: any) => setMail(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Confirm mail address"
            required={true}
            value={mailConfirm}
            onChange={(ev: any) => setMailConfirm(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Password"
            type="password"
            required={true}
            value={password}
            onChange={(ev: any) => setPassword(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Confirm password"
            type="password"
            required={true}
            value={passwordConfirm}
            onChange={(ev: any) => setPasswordConfirm(ev.currentTarget.value)}
          />
          <Button
            className="outline-style-d"
            icon="tick-circle"
            type="submit"
            disabled={!validateForm()}
          >
            Create an account
          </Button>
        </div>
      </form>
    </div>
  );
};
